const results = $input.first().json.results || [];
if (!results.length) throw new Error('No TGF pages found in Notion. Make sure a page with "TGF Metric Update" in the title exists and is shared with your integration.');

// Take the most recently edited page
const page = results[0];
const pageId = page.id.replace(/-/g, '');
const pageTitle = page.properties?.title?.title?.[0]?.plain_text ||
  page.properties?.Name?.title?.[0]?.plain_text ||
  'TGF Update';
const lastEdited = page.last_edited_time;

// Detect quarter from title or date
function detectQuarter(title, editedAt) {
  // Try Q1/Q2/Q3/Q4 + year pattern in title
  const qMatch = title.match(/Q([1-4])[-\s]*(20\d{2}|\d{2})/i);
  if (qMatch) {
    const y = qMatch[2].length === 2 ? '20' + qMatch[2] : qMatch[2];
    return `Q${qMatch[1]}-${y}`;
  }
  // Try date prefix like "8-Jan-26" or "15-Apr-26"
  const months = {jan:1,feb:2,mar:3,apr:4,may:5,jun:6,jul:7,aug:8,sep:9,oct:10,nov:11,dec:12};
  const dateMatch = title.match(/(\d{1,2})[- ]([A-Za-z]{3})[- ]?(\d{2,4})/i);
  if (dateMatch) {
    const m = months[dateMatch[2].toLowerCase()];
    const y = parseInt(dateMatch[3].length === 2 ? '20' + dateMatch[3] : dateMatch[3]);
    if (m && y) return `Q${Math.ceil(m/3)}-${y}`;
  }
  // Fall back to edit timestamp
  const d = new Date(editedAt);
  const m = d.getMonth() + 1;
  return `Q${Math.ceil(m/3)}-${d.getFullYear()}`;
}

const quarterKey = detectQuarter(pageTitle, lastEdited);
const quarterLabel = quarterKey.replace('-', ' ');

console.log(`Found page: "${pageTitle}" → ${quarterKey}`);

return [{ json: { pageId, pageTitle, quarterKey, quarterLabel, lastEdited } }];

const blocks = $input.first().json.results || [];
const meta = $('Extract Latest Page ID').first().json;

// Find first table block
const tableBlock = blocks.find(b => b.type === 'table');
if (!tableBlock) throw new Error(`No table found in page "${meta.pageTitle}". Check the Notion page has a table.`);

console.log(`Found table block: ${tableBlock.id}`);

return [{ json: {
  ...meta,
  tableBlockId: tableBlock.id.replace(/-/g, ''),
  hasColumnHeader: tableBlock.table?.has_column_header ?? true
}}];

const rows = $input.first().json.results || [];
const meta = $('Find Table Block ID').first().json;

if (!rows.length) throw new Error('Table has no rows.');

// ── Helper: extract plain text from a Notion rich-text cell ──
function cellText(cell) {
  if (!Array.isArray(cell)) return '';
  return cell.map(rt => rt.plain_text || '').join('').trim();
}

// ── Helper: check if any part of a cell is strikethrough ──
function isStrikethrough(cell) {
  if (!Array.isArray(cell)) return false;
  return cell.some(rt => rt.annotations?.strikethrough === true);
}

// ── Read header row to map columns ──
const headerCells = rows[0]?.table_row?.cells || [];
const headers = headerCells.map(c => cellText(c).toLowerCase());

const COL_FIND = (keywords) => {
  const idx = headers.findIndex(h => keywords.some(k => h.includes(k)));
  return idx;
};

const COL = {
  name:    COL_FIND(['milestone', 'name', 'metric', 'feature']) !== -1 ? COL_FIND(['milestone', 'name', 'metric', 'feature']) : 0,
  fn:      COL_FIND(['function', 'fn', 'team'])                 !== -1 ? COL_FIND(['function', 'fn', 'team'])                 : 1,
  target:  COL_FIND(['target', 'goal'])                         !== -1 ? COL_FIND(['target', 'goal'])                         : 3,
  current: COL_FIND(['current', 'actual', 'status', 'metric'])  !== -1 ? COL_FIND(['current', 'actual', 'status', 'metric'])  : 4,
};
// Ensure current != name if they resolved to same column
if (COL.current === COL.name) COL.current = 4;

console.log('Column map:', JSON.stringify(COL));
console.log('Headers found:', headers);

// ── Known ID lookup (handles template variations) ──
const ID_MAP = [
  [['net expansion', 'upsell', 'revenue expansion'], 'net-expansion'],
  [['logo retention', 'client retention', 'churn'], 'logo-retention'],
  [['qbr', 'quarterly business'], 'qbr'],
  [['true adoption', 'platform adoption', 'utilization', 'utilisation'], 'adoption'],
  [['csat', 'customer experience', 'customer satisfaction', 'satisfaction score'], 'csat'],
  [['ticket lifecycle', 'resolution time', 'lifecycle management', 'follow-up'], 'lifecycle'],
  [['process adherence', 'qa score', 'quality', 'audit'], 'qa'],
  [['bot accuracy', 'automation', 'knowledge', 'llm', 'bot performance'], 'automation'],
  [['operational governance', 'governance', 'sop', 'dashboard publishing'], 'governance'],
  [['gross margin', 'gm', 'managed services margin'], 'gm'],
  [['proctor', 'utilisation', 'proctoring'], 'proctor'],
  [['pipeline', 'expansion pipeline', 'revenue pipeline'], 'pipeline'],
  [['go live', 'golive', 'go-live', 'sla deployment'], 'golive'],
];

function resolveId(name) {
  const lower = name.toLowerCase();
  for (const [keywords, id] of ID_MAP) {
    if (keywords.some(k => lower.includes(k))) return id;
  }
  return lower.replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

function detectFn(fnText, name) {
  const t = fnText.toLowerCase().trim();
  if (['cs', 'customer success'].includes(t)) return 'CS';
  if (['ts', 'technical support', 'support'].includes(t)) return 'TS';
  if (['ms', 'managed services'].includes(t)) return 'MS';
  const n = name.toLowerCase();
  if (['csat','resolution','qa','bot','governance','ticket','lifecycle','sop'].some(k => n.includes(k))) return 'TS';
  if (['gross margin','proctor','gm'].some(k => n.includes(k))) return 'MS';
  return 'CS';
}

function detectType(targetText, currentText, name) {
  const all = (targetText + ' ' + currentText + ' ' + name).toLowerCase();
  if (all.match(/\$[0-9]/) || all.includes(' k ') || all.includes('pipeline') || all.includes('expansion $')) return 'financial';
  if (all.match(/[0-9]h[ 0-9m]/) || all.includes('resolution') || all.includes('response time') || all.includes('hours')) return 'time';
  if (all.includes('csat') || all.includes('score') || (all.match(/[≥≤][\s]*[0-9]\.[0-9]/))) return 'score';
  if (all.includes('go live') || all.includes('integration') || all.includes('milestone') || all.includes('in progress')) return 'milestone';
  return 'pct';
}

function parseValue(text, type) {
  if (!text) return null;
  const clean = text.replace(/~~/g, '').replace(/\*\*/g, '').trim();
  if (!clean || ['', 'pending', 'n/a', 'tbd', 'in progress', '-', '—'].includes(clean.toLowerCase())) return null;
  // Financial
  const fin = clean.match(/\$([0-9,.]+)\s*([KMB]?)/i);
  if (fin) {
    let v = parseFloat(fin[1].replace(/,/g, ''));
    const m = fin[2].toUpperCase();
    if (m === 'K') v *= 1000;
    if (m === 'M') v *= 1000000;
    if (m === 'B') v *= 1000000000;
    return Math.round(v);
  }
  // Percentage
  const pct = clean.match(/([0-9.]+)\s*%/);
  if (pct) return parseFloat(pct[1]);
  // Time: 8h 5m → 8.08
  const time = clean.match(/([0-9]+)\s*h(?:\s*([0-9]+)\s*m)?/i);
  if (time) return Math.round((parseInt(time[1]) + (time[2] ? parseInt(time[2])/60 : 0)) * 100) / 100;
  // Score / plain number
  const num = clean.match(/[≥≤><=~]?\s*([0-9]+(?:\.[0-9]+)?)/);
  if (num) return parseFloat(num[1]);
  return null;
}

const metrics = [];

for (let i = 1; i < rows.length; i++) {  // skip header row (i=0)
  const cells = rows[i]?.table_row?.cells || [];
  const nameRaw = cellText(cells[COL.name] || []);
  if (!nameRaw || nameRaw.trim() === '') continue;  // skip empty rows

  const name    = nameRaw.replace(/\*\*/g, '').split('\n')[0].trim();
  const fnRaw   = cellText(cells[COL.fn] || []);
  const targetT = cellText(cells[COL.target] || []);
  const currentT = cellText(cells[COL.current] || []);
  const struck  = isStrikethrough(cells[COL.current] || []);

  const type = detectType(targetT, currentT, name);
  const tV   = parseValue(targetT, type);
  const cV   = struck ? null : parseValue(currentT, type);
  const conf = struck ? 0.3 : (cV === null ? 0 : 0.85);

  metrics.push({
    id: resolveId(name),
    name,
    fn: detectFn(fnRaw, name),
    target: targetT || '',
    tV,
    type,
    current: struck ? `~~${currentT}~~` : (currentT || null),
    cV,
    lq: null,
    lqV: null,
    conf
  });
}

console.log(`Parsed ${metrics.length} metrics from Notion table`);

if (!metrics.length) throw new Error('Parsed 0 metrics — check the table column headers in Notion match expected names.');

return [{ json: { ...meta, metrics } }];

const ghFile   = $('Get dashboard.html from GitHub').first().json;
const parsed   = $('Parse Metrics from Table').first().json;

const { quarterKey, quarterLabel, pageTitle, metrics } = parsed;
const sha = ghFile.sha;

// Decode current file content
let html = Buffer.from(ghFile.content, 'base64').toString('utf8');

// ── Build the lq/lqV values from the previous quarter's data ──
// Extract existing CURRENT_Q and CURRENT_DATA to use as lq reference
const prevQMatch = html.match(/const CURRENT_Q='([^']+)'/);
const prevQ = prevQMatch ? prevQMatch[1] : null;

// Pull previous quarter metrics for lq references
const prevMetricsMap = {};
if (prevQ) {
  // Scan H_HISTORY for last known values of each metric id
  const histBlock = html.match(/const H_HISTORY=\{([\s\S]*?)\};\s*const H=/);
  if (histBlock) {
    const allLqMatches = [...histBlock[1].matchAll(/id:'([^']+)'[^}]*cV:(null|[0-9.]+)/g)];
    // Use the last occurrence of each id (most recent historical quarter)
    allLqMatches.forEach(m => { prevMetricsMap[m[1]] = m[2] === 'null' ? null : parseFloat(m[2]); });
  }
  // Also read current CURRENT_DATA block for lq
  const curStart = html.indexOf('// <<<TGF_CURRENT_START>>>');
  const curEnd   = html.indexOf('// <<<TGF_CURRENT_END>>>');
  if (curStart !== -1 && curEnd !== -1) {
    const curBlock = html.slice(curStart, curEnd);
    const curMatches = [...curBlock.matchAll(/id:'([^']+)'[^}]*cV:(null|[0-9.]+)/g)];
    curMatches.forEach(m => { prevMetricsMap[m[1]] = m[2] === 'null' ? null : parseFloat(m[2]); });
  }
}

const prevQLabel = prevQ ? prevQ.replace('-', ' ') : 'prev';

// Enrich metrics with lq/lqV from previous quarter
const enrichedMetrics = metrics.map(m => ({
  ...m,
  lq: prevMetricsMap[m.id] != null ? `${prevMetricsMap[m.id]} (${prevQLabel})` : null,
  lqV: prevMetricsMap[m.id] ?? null
}));

// ── Build JS literal for each metric ──
function esc(s) { return String(s || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'"); }
function metricJS(m) {
  return `  {id:'${esc(m.id)}',name:'${esc(m.name)}',fn:'${m.fn}',target:'${esc(m.target)}',tV:${m.tV ?? 'null'},type:'${m.type}',current:${m.current === null ? 'null' : `'${esc(m.current)}'`},cV:${m.cV ?? 'null'},lq:${m.lq ? `'${esc(m.lq)}'` : 'null'},lqV:${m.lqV ?? 'null'},conf:${m.conf}}`;
}

const metricsBlock = enrichedMetrics.map(metricJS).join(',\n');
const dateStr = new Date().toISOString().split('T')[0];

const newCurrentBlock =
`// <<<TGF_CURRENT_START>>>
const CURRENT_Q='${quarterKey}';
const CURRENT_DATA={label:'${quarterLabel}',date:'${dateStr}',pageTitle:'${esc(pageTitle)}',metrics:[\n${metricsBlock},\n]};
// <<<TGF_CURRENT_END>>>`;

// ── Replace between markers ──
const startMarker = '// <<<TGF_CURRENT_START>>>';
const endMarker   = '// <<<TGF_CURRENT_END>>>';
const startIdx = html.indexOf(startMarker);
const endIdx   = html.indexOf(endMarker);
if (startIdx === -1 || endIdx === -1) throw new Error('TGF data markers not found in dashboard.html');

const updatedHtml = html.slice(0, startIdx) + newCurrentBlock + html.slice(endIdx + endMarker.length);

// ── Also update loadQ boot call to point at new quarter ──
const finalHtml = updatedHtml.replace(
  /loadQ\(CURRENT_Q\)/g,
  'loadQ(CURRENT_Q)'
);

console.log(`Updated dashboard: ${quarterKey} with ${enrichedMetrics.length} metrics`);

return [{ json: {
  content: Buffer.from(finalHtml).toString('base64'),
  sha,
  quarterKey,
  metricsCount: enrichedMetrics.length,
  commitMessage: `chore: sync ${quarterKey} metrics from Notion (${dateStr})`
}}];
